def count_up(start, stop):
    n = start
    while n <= stop:
        yield n  # pause here, send n, wait for next call
        n += 1

gen = count_up(1, 5)
for number in gen:
    print(number)

def flat_list(nested):
    for items in nested:
        # TODO: instead of looping again, use 'yield from items'
        for item in items:
            yield item

data = [[1, 2, 3], [4, 5], [6, 7, 8, 9]]
print(list(flat_list(data)))

